bool isValid(const string& s) {
    stack<char> opened;
    unordered_map<char, char> pairs = {{')', '('}, {']', '['}, {'}', '{'}};
    for (char c : s) {
        if (c == '(' || c == '[' || c == '{') opened.push(c);
        else if (opened.empty() || opened.top() != pairs[c]) return false;
        else opened.pop();
    }
    return opened.empty();
}

